1	//! Built-in dispatch for the Saga 11 model DSL.
2	//!
3	//! `linear(in_dim, out_dim, seed)` creates a fresh `ModelSpec::Linear`
4	//! whose `W` and `b` parameters are stored in the environment under
5	//! generated names. `apply(model_ident, X)` looks up the model and
6	//! evaluates it on the given input.
7	
8	use mlpl_array::{DenseArray, Shape};
9	use mlpl_parser::Expr;
10	use mlpl_trace::Trace;
11	
12	use crate::env::Environment;
13	use crate::error::EvalError;
14	use crate::model::{ActKind, ModelSpec};
15	use crate::value::Value;
16	
17	/// `linear(in_dim, out_dim, seed)`.
18	pub(crate) fn eval_linear(args: &[Expr], env: &mut Environment) -> Result<ModelSpec, EvalError> {
19	    if args.len() != 3 {
20	        return Err(EvalError::BadArity {
21	            func: "linear".into(),
22	            expected: 3,
23	            got: args.len(),
24	        });
25	    }
26	    let in_dim = scalar_usize(&args[0], env, "linear")?;
27	    let out_dim = scalar_usize(&args[1], env, "linear")?;
28	    let seed = scalar_f64(&args[2], env, "linear")?;
29	
30	    let id = env.next_model_id;
31	    env.next_model_id += 1;
32	    let w_name = format!("__linear_W_{id}");
33	    let b_name = format!("__linear_b_{id}");
34	
35	    // W <- randn(seed, [in_dim, out_dim]) * 0.5 (Xavier-ish small).
36	    let w_init = mlpl_runtime::call_builtin(
37	        "randn",
38	        vec![
39	            DenseArray::from_scalar(seed),
40	            DenseArray::new(Shape::new(vec![2]), vec![in_dim as f64, out_dim as f64])?,
41	        ],
42	    )?;
43	    let w_data: Vec<f64> = w_init.data().iter().map(|v| v * 0.5).collect();
44	    let w = DenseArray::new(Shape::new(vec![in_dim, out_dim]), w_data)?;
45	    env.set_param(w_name.clone(), w);
46	
47	    let b = DenseArray::zeros(Shape::new(vec![1, out_dim]));
48	    env.set_param(b_name.clone(), b);
49	
50	    Ok(ModelSpec::Linear {
51	        w: w_name,
52	        b: b_name,
53	    })
54	}
55	
56	/// `embed(vocab_size, d_model, seed)` -- token embedding layer.
57	/// Allocates a single `[vocab, d_model]` lookup table parameter,
58	/// initialised with `randn(seed, [vocab, d_model]) * 0.1` (small to
59	/// avoid blowing up early softmax logits in language-model demos).
60	pub(crate) fn eval_embedding(args: &[Expr], env: &mut Environment) -> Result<ModelSpec, EvalError> {
61	    if args.len() != 3 {
62	        return Err(EvalError::BadArity {
63	            func: "embed".into(),
64	            expected: 3,
65	            got: args.len(),
66	        });
67	    }
68	    let vocab = scalar_usize(&args[0], env, "embed")?;
69	    let d_model = scalar_usize(&args[1], env, "embed")?;
70	    let seed = scalar_f64(&args[2], env, "embed")?;
71	
72	    let id = env.next_model_id;
73	    env.next_model_id += 1;
74	    let table_name = format!("__embed_E_{id}");
75	
76	    let table_init = mlpl_runtime::call_builtin(
77	        "randn",
78	        vec![
79	            DenseArray::from_scalar(seed),
80	            DenseArray::new(Shape::new(vec![2]), vec![vocab as f64, d_model as f64])?,
81	        ],
82	    )?;
83	    let table_data: Vec<f64> = table_init.data().iter().map(|v| v * 0.1).collect();
84	    let table = DenseArray::new(Shape::new(vec![vocab, d_model]), table_data)?;
85	    env.set_param(table_name.clone(), table);
86	
87	    Ok(ModelSpec::Embedding {
88	        table: table_name,
89	        vocab,
90	        d_model,
91	    })
92	}
93	
94	/// `chain(layer_a, layer_b, ...)`. Each argument must evaluate to a
95	/// `Value::Model`.
96	pub(crate) fn eval_chain(args: &[Expr], env: &mut Environment) -> Result<ModelSpec, EvalError> {
97	    let mut children = Vec::with_capacity(args.len());
98	    for (i, arg) in args.iter().enumerate() {
99	        match crate::eval::eval_expr(arg, env, &mut None)? {
100	            Value::Model(m) => children.push(m),
101	            _ => {
102	                return Err(EvalError::Unsupported(format!(
103	                    "chain: argument {i} did not evaluate to a model"
104	                )));
105	            }
106	        }
107	    }
108	    Ok(ModelSpec::Chain(children))
109	}
110	
111	/// `residual(inner_model)`. Wraps a single model argument in a
112	/// skip-connection node.
113	pub(crate) fn eval_residual(args: &[Expr], env: &mut Environment) -> Result<ModelSpec, EvalError> {
114	    if args.len() != 1 {
115	        return Err(EvalError::BadArity {
116	            func: "residual".into(),
117	            expected: 1,
118	            got: args.len(),
119	        });
120	    }
121	    match crate::eval::eval_expr(&args[0], env, &mut None)? {
122	        Value::Model(m) => Ok(ModelSpec::Residual(Box::new(m))),
123	        _ => Err(EvalError::Unsupported(
124	            "residual: argument must evaluate to a model".into(),
125	        )),
126	    }
127	}
128	
129	/// `attention(d_model, heads, seed)` -- multi-head self-attention.
130	/// Allocates four `[d_model, d_model]` weight params and registers
131	/// them as trainable in the env. Names are namespaced by the env's
132	/// `next_model_id` so multiple attention layers do not collide.
133	pub(crate) fn eval_attention(args: &[Expr], env: &mut Environment) -> Result<ModelSpec, EvalError> {
134	    if args.len() != 3 {
135	        return Err(EvalError::BadArity {
136	            func: "attention".into(),
137	            expected: 3,
138	            got: args.len(),
139	        });
140	    }
141	    let d_model = scalar_usize(&args[0], env, "attention")?;
142	    let heads = scalar_usize(&args[1], env, "attention")?;
143	    let seed = scalar_f64(&args[2], env, "attention")?;
144	    if heads == 0 || d_model % heads != 0 {
145	        return Err(EvalError::Unsupported(format!(
146	            "attention: d_model ({d_model}) must be divisible by heads ({heads})"
147	        )));
148	    }
149	    let id = env.next_model_id;
150	    env.next_model_id += 1;
151	    let wq = format!("__attn_Wq_{id}");
152	    let wk = format!("__attn_Wk_{id}");
153	    let wv = format!("__attn_Wv_{id}");
154	    let wo = format!("__attn_Wo_{id}");
155	    // Use a small offset on the seed so the four projections do not
156	    // start out identical.
157	    for (i, name) in [&wq, &wk, &wv, &wo].iter().enumerate() {
158	        let init = mlpl_runtime::call_builtin(
159	            "randn",
160	            vec![
161	                DenseArray::from_scalar(seed + i as f64),
162	                DenseArray::new(Shape::new(vec![2]), vec![d_model as f64, d_model as f64])?,
163	            ],
164	        )?;
165	        let scaled: Vec<f64> = init.data().iter().map(|v| v * 0.5).collect();
166	        let arr = DenseArray::new(Shape::new(vec![d_model, d_model]), scaled)?;
167	        env.set_param((*name).clone(), arr);
168	    }
169	    Ok(ModelSpec::Attention {
170	        wq,
171	        wk,
172	        wv,
173	        wo,
174	        d_model,
175	        heads,
176	    })
177	}
178	
179	/// `rms_norm(dim)` -- parameter-free per-row RMS normalization.
180	pub(crate) fn eval_rms_norm(args: &[Expr], env: &mut Environment) -> Result<ModelSpec, EvalError> {
181	    if args.len() != 1 {
182	        return Err(EvalError::BadArity {
183	            func: "rms_norm".into(),
184	            expected: 1,
185	            got: args.len(),
186	        });
187	    }
188	    let dim = scalar_usize(&args[0], env, "rms_norm")?;
189	    Ok(ModelSpec::RmsNorm { dim })
190	}
191	
192	/// Parameter-free activation layer constructors. Returns the
193	/// matching `ActKind` if `name` is recognized.
194	#[must_use]
195	pub(crate) fn activation_kind(name: &str) -> Option<ActKind> {
196	    Some(match name {
197	        "tanh_layer" => ActKind::Tanh,
198	        "relu_layer" => ActKind::Relu,
199	        "softmax_layer" => ActKind::Softmax,
200	        _ => return None,
201	    })
202	}
203	
204	/// `apply(model_ident, X)`.
205	pub(crate) fn eval_apply(
206	    args: &[Expr],
207	    env: &mut Environment,
208	    trace: &mut Option<&mut Trace>,
209	) -> Result<DenseArray, EvalError> {
210	    if args.len() != 2 {
211	        return Err(EvalError::BadArity {
212	            func: "apply".into(),
213	            expected: 2,
214	            got: args.len(),
215	        });
216	    }
217	    let model_name = match &args[0] {
218	        Expr::Ident(n, _) => n.clone(),
219	        _ => {
220	            return Err(EvalError::Unsupported(
221	                "apply: first argument must be a model identifier".into(),
222	            ));
223	        }
224	    };
225	    let model = env
226	        .get_model(&model_name)
227	        .cloned()
228	        .ok_or_else(|| EvalError::UndefinedVariable(model_name.clone()))?;
229	    let x = crate::eval::eval_expr(&args[1], env, trace)?.into_array()?;
230	    apply_model(&model, &x, env)
231	}
232	
233	fn apply_model(
234	    model: &ModelSpec,
235	    x: &DenseArray,
236	    env: &Environment,
237	) -> Result<DenseArray, EvalError> {
238	    match model {
239	        ModelSpec::Linear { w, b } => {
240	            let w_arr = env
241	                .get(w)
242	                .ok_or_else(|| EvalError::UndefinedVariable(w.clone()))?;
243	            let b_arr = env
244	                .get(b)
245	                .ok_or_else(|| EvalError::UndefinedVariable(b.clone()))?;
246	            let xw = x.matmul(w_arr)?;
247	            // Broadcast b ([1, out]) up to [n, out] via ones([n, 1]) @ b.
248	            let n = xw.shape().dims()[0];
249	            let ones = DenseArray::new(Shape::new(vec![n, 1]), vec![1.0; n])?;
250	            let b_broadcast = ones.matmul(b_arr)?;
251	            Ok(xw.apply_binop(&b_broadcast, |a, c| a + c)?)
252	        }
253	        ModelSpec::Chain(children) => {
254	            let mut cur = x.clone();
255	            for child in children {
256	                cur = apply_model(child, &cur, env)?;
257	            }
258	            Ok(cur)
259	        }
260	        ModelSpec::Activation(kind) => match kind {
261	            ActKind::Tanh => Ok(x.map(f64::tanh)),
262	            ActKind::Relu => Ok(x.map(|v| if v > 0.0 { v } else { 0.0 })),
263	            ActKind::Softmax => Ok(mlpl_runtime::call_builtin(
264	                "softmax",
265	                vec![x.clone(), DenseArray::from_scalar(1.0)],
266	            )?),
267	        },
268	        ModelSpec::Residual(inner) => {
269	            let inner_out = apply_model(inner, x, env)?;
270	            if inner_out.shape() != x.shape() {
271	                return Err(EvalError::Unsupported(
272	                    "residual: inner block must preserve input shape".into(),
273	                ));
274	            }
275	            Ok(x.apply_binop(&inner_out, |a, b| a + b)?)
276	        }
277	        ModelSpec::RmsNorm { .. } => apply_rms_norm(x),
278	        ModelSpec::Attention {
279	            wq,
280	            wk,
281	            wv,
282	            wo,
283	            d_model,
284	            heads,
285	        } => apply_attention(x, wq, wk, wv, wo, *d_model, *heads, env),
286	        ModelSpec::Embedding { table, vocab, .. } => {
287	            let t = env
288	                .get(table)
289	                .ok_or_else(|| EvalError::UndefinedVariable(table.clone()))?;
290	            Ok(tokens_to_onehot(x, *vocab)?.matmul(t)?)
291	        }
292	    }
293	}
294	
295	/// Convert an integer-valued token id array (1-D `[N]`) into a
296	/// `[N, vocab]` one-hot matrix. Token ids must be non-negative
297	/// integers in `[0, vocab)`. The one-hot trick lets the embedding
298	/// gather lower to a plain matmul, so the existing autograd tape
299	/// can backprop into the table without a new gather primitive.
300	fn tokens_to_onehot(tokens: &DenseArray, vocab: usize) -> Result<DenseArray, EvalError> {
301	    let dims = tokens.shape().dims();
302	    if dims.len() != 1 {
303	        return Err(EvalError::Unsupported(format!(
304	            "embed: tokens must be a 1-D [N] array, got shape {dims:?}"
305	        )));
306	    }
307	    let n = dims[0];
308	    let mut data = vec![0.0_f64; n * vocab];
309	    for (row, &id_f) in tokens.data().iter().enumerate() {
310	        if !id_f.is_finite() || id_f < 0.0 || id_f.fract() != 0.0 {
311	            return Err(EvalError::Unsupported(format!(
312	                "embed: token at position {row} = {id_f} is not a non-negative integer"
313	            )));
314	        }
315	        let id = id_f as usize;
316	        if id >= vocab {
317	            return Err(EvalError::Unsupported(format!(
318	                "embed: token at position {row} = {id} out of vocab range [0, {vocab})"
319	            )));
320	        }
321	        data[row * vocab + id] = 1.0;
322	    }
323	    DenseArray::new(Shape::new(vec![n, vocab]), data)
324	        .map_err(|e| EvalError::Unsupported(format!("embed: one-hot construction failed: {e}")))
325	}
326	
327	#[allow(clippy::too_many_arguments)]
328	fn apply_attention(
329	    x: &DenseArray,
330	    wq: &str,
331	    wk: &str,
332	    wv: &str,
333	    wo: &str,
334	    d_model: usize,
335	    heads: usize,
336	    env: &Environment,
337	) -> Result<DenseArray, EvalError> {
338	    let dims = x.shape().dims();
339	    if dims.len() != 2 || dims[1] != d_model {
340	        return Err(EvalError::Unsupported(format!(
341	            "attention: input must be [seq, {d_model}], got {:?}",
342	            dims
343	        )));
344	    }
345	    let seq = dims[0];
346	    let d_k = d_model / heads;
347	
348	    let wq_a = env
349	        .get(wq)
350	        .ok_or_else(|| EvalError::UndefinedVariable(wq.into()))?;
351	    let wk_a = env
352	        .get(wk)
353	        .ok_or_else(|| EvalError::UndefinedVariable(wk.into()))?;
354	    let wv_a = env
355	        .get(wv)
356	        .ok_or_else(|| EvalError::UndefinedVariable(wv.into()))?;
357	    let wo_a = env
358	        .get(wo)
359	        .ok_or_else(|| EvalError::UndefinedVariable(wo.into()))?;
360	
361	    let q = x.matmul(wq_a)?;
362	    let k = x.matmul(wk_a)?;
363	    let v = x.matmul(wv_a)?;
364	
365	    let scale = 1.0 / (d_k as f64).sqrt();
366	    // Per-head attention. Concatenate per-head outputs back into a
367	    // [seq, d_model] matrix in the same column layout as the input.
368	    let mut concat = vec![0.0_f64; seq * d_model];
369	    for h in 0..heads {
370	        let q_h = slice_cols(&q, h * d_k, d_k)?;
371	        let k_h = slice_cols(&k, h * d_k, d_k)?;
372	        let v_h = slice_cols(&v, h * d_k, d_k)?;
373	        let scores = q_h.matmul(&k_h.transpose())?;
374	        let scaled: Vec<f64> = scores.data().iter().map(|s| s * scale).collect();
375	        let scores_scaled = DenseArray::new(Shape::new(vec![seq, seq]), scaled)?;
376	        let attn = mlpl_runtime::call_builtin(
377	            "softmax",
378	            vec![scores_scaled, DenseArray::from_scalar(1.0)],
379	        )?;
380	        let head_out = attn.matmul(&v_h)?; // [seq, d_k]
381	        for r in 0..seq {
382	            for c in 0..d_k {
383	                concat[r * d_model + h * d_k + c] = head_out.data()[r * d_k + c];
384	            }
385	        }
386	    }
387	    let concat = DenseArray::new(Shape::new(vec![seq, d_model]), concat)?;
388	    Ok(concat.matmul(wo_a)?)
389	}
390	
391	/// Extract `width` consecutive columns starting at `start` from a
392	/// rank-2 matrix.
393	fn slice_cols(x: &DenseArray, start: usize, width: usize) -> Result<DenseArray, EvalError> {
394	    let dims = x.shape().dims();
395	    let rows = dims[0];
396	    let cols = dims[1];
397	    let mut out = Vec::with_capacity(rows * width);
398	    for r in 0..rows {
399	        for c in 0..width {
400	            out.push(x.data()[r * cols + start + c]);
401	        }
402	    }
403	    Ok(DenseArray::new(Shape::new(vec![rows, width]), out)?)
404	}
405	
406	// Tape lowering of the model DSL lives in `crate::model_tape`; the
407	// eager forward pass below stays here.
408	
409	/// Per-row RMS normalization: `y[i, :] = x[i, :] / sqrt(mean(x[i, :]^2) + eps)`.
410	fn apply_rms_norm(x: &DenseArray) -> Result<DenseArray, EvalError> {
411	    let dims = x.shape().dims();
412	    if dims.len() != 2 {
413	        return Err(EvalError::Unsupported(
414	            "rms_norm: input must be a rank-2 [rows, cols] matrix".into(),
415	        ));
416	    }
417	    let rows = dims[0];
418	    let cols = dims[1];
419	    let eps = 1e-8;
420	    let src = x.data();
421	    let mut out = Vec::with_capacity(src.len());
422	    for r in 0..rows {
423	        let row = &src[r * cols..(r + 1) * cols];
424	        let mean_sq: f64 = row.iter().map(|v| v * v).sum::<f64>() / cols.max(1) as f64;
425	        let scale = 1.0 / (mean_sq + eps).sqrt();
426	        for v in row {
427	            out.push(v * scale);
428	        }
429	    }
430	    Ok(DenseArray::new(Shape::new(vec![rows, cols]), out)?)
431	}
432	
433	fn scalar_f64(expr: &Expr, env: &mut Environment, func: &str) -> Result<f64, EvalError> {
434	    let arr = crate::eval::eval_expr(expr, env, &mut None)?.into_array()?;
435	    if arr.rank() != 0 {
436	        return Err(EvalError::Unsupported(format!(
437	            "{func}: expected a scalar argument"
438	        )));
439	    }
440	    Ok(arr.data()[0])
441	}
442	
443	fn scalar_usize(expr: &Expr, env: &mut Environment, func: &str) -> Result<usize, EvalError> {
444	    let v = scalar_f64(expr, env, func)?;
445	    if v < 0.0 || v.fract() != 0.0 {
446	        return Err(EvalError::Unsupported(format!(
447	            "{func}: dimension must be a non-negative integer"
448	        )));
449	    }
450	    Ok(v as usize)
451	}
