1	//! Tape-side lowering of the Saga 11 model DSL.
2	//!
3	//! This is the autograd twin of `model_dispatch::apply_model`: given
4	//! a `ModelSpec` and an input `Tensor` handle, it walks the model
5	//! tree and emits the same primitive ops onto the autograd tape so
6	//! that `grad(loss_with_apply, ...)` -- and therefore every optimizer
7	//! built on top of it -- can route gradients back to each layer's
8	//! trainable parameter leaves.
9	//!
10	//! Coverage today:
11	//!
12	//! - `linear`, `chain`, activation layers, `residual`, `rms_norm`,
13	//!   and single-head `attention` are fully lowered.
14	//! - Multi-head attention (`heads > 1`) is not yet supported; the
15	//!   per-head slicing it needs is not expressible with the current
16	//!   `Tensor` op surface. Use `heads = 1` or inline the per-head
17	//!   forward pass in the loss expression for now.
18	
19	use std::collections::HashMap;
20	use std::rc::Rc;
21	
22	use mlpl_array::{DenseArray, Shape};
23	use mlpl_autograd::{Tape, Tensor};
24	
25	use crate::error::EvalError;
26	use crate::model::{ActKind, ModelSpec};
27	
28	/// Tape-side analogue of `model_dispatch::apply_model`. Walks the
29	/// model and emits the matching primitive ops on the autograd tape.
30	pub(crate) fn apply_model_tape(
31	    model: &ModelSpec,
32	    x: Tensor,
33	    tape: &Rc<Tape>,
34	    params: &HashMap<String, Tensor>,
35	) -> Result<Tensor, EvalError> {
36	    match model {
37	        ModelSpec::Linear { w, b } => linear_tape(&x, w, b, tape, params),
38	        ModelSpec::Chain(children) => {
39	            let mut cur = x;
40	            for child in children {
41	                cur = apply_model_tape(child, cur, tape, params)?;
42	            }
43	            Ok(cur)
44	        }
45	        ModelSpec::Activation(kind) => Ok(match kind {
46	            ActKind::Tanh => x.tanh(),
47	            ActKind::Relu => x.relu(),
48	            ActKind::Softmax => x.softmax(),
49	        }),
50	        ModelSpec::Residual(inner) => {
51	            let inner_out = apply_model_tape(inner, x.clone(), tape, params)?;
52	            Ok(x.add(&inner_out))
53	        }
54	        ModelSpec::RmsNorm { .. } => rms_norm_tape(&x, tape),
55	        ModelSpec::Embedding { table, vocab, .. } => {
56	            let table_t = params
57	                .get(table)
58	                .cloned()
59	                .ok_or_else(|| EvalError::UndefinedVariable(table.clone()))?;
60	            // The token id array enters the tape as a non-trainable
61	            // input leaf; we use its eager value to build a one-hot
62	            // matrix and matmul against the trainable table tensor.
63	            // Backprop then routes through matmul straight into the
64	            // table's gradient buffer.
65	            let tokens_arr = x.value().clone();
66	            let onehot_arr = onehot_from_tokens(&tokens_arr, *vocab)?;
67	            let onehot_t = Tensor::leaf(Rc::clone(tape), onehot_arr, false);
68	            Ok(onehot_t.matmul(&table_t))
69	        }
70	        ModelSpec::Attention {
71	            wq,
72	            wk,
73	            wv,
74	            wo,
75	            d_model,
76	            heads,
77	        } => {
78	            if *heads != 1 {
79	                return Err(EvalError::Unsupported(format!(
80	                    "grad: apply() through multi-head attention (heads={heads}) is not \
81	                     yet supported on the autograd tape; use heads=1 or inline the \
82	                     per-head forward pass in the loss expression"
83	                )));
84	            }
85	            let inputs = AttentionInputs {
86	                wq,
87	                wk,
88	                wv,
89	                wo,
90	                d_model: *d_model,
91	            };
92	            attention_single_head_tape(&x, &inputs, tape, params)
93	        }
94	    }
95	}
96	
97	fn linear_tape(
98	    x: &Tensor,
99	    w: &str,
100	    b: &str,
101	    tape: &Rc<Tape>,
102	    params: &HashMap<String, Tensor>,
103	) -> Result<Tensor, EvalError> {
104	    let w_t = params
105	        .get(w)
106	        .cloned()
107	        .ok_or_else(|| EvalError::UndefinedVariable(w.into()))?;
108	    let b_t = params
109	        .get(b)
110	        .cloned()
111	        .ok_or_else(|| EvalError::UndefinedVariable(b.into()))?;
112	    let xw = x.matmul(&w_t);
113	    // b is [1, out]; lift to [n, out] via ones([n, 1]) @ b so the
114	    // tape graph matches the hand-rolled broadcast form exactly.
115	    let n = xw.value().shape().dims()[0];
116	    let ones_arr = DenseArray::new(Shape::new(vec![n, 1]), vec![1.0; n])?;
117	    let ones_t = Tensor::leaf(Rc::clone(tape), ones_arr, false);
118	    Ok(xw.add(&ones_t.matmul(&b_t)))
119	}
120	
121	/// Per-row RMS normalization on the tape:
122	/// `y[i, :] = x[i, :] / sqrt(mean(x[i, :]^2) + eps)`.
123	/// `sqrt(v)` is encoded as `exp(-0.5 * log(v))` because the tape
124	/// does not yet expose a direct sqrt op. Per-row mean is encoded as
125	/// `matmul(x, ones([cols, 1])) / cols`, and the broadcast back to
126	/// `[rows, cols]` as `rsqrt @ ones([1, cols])`.
127	fn rms_norm_tape(x: &Tensor, tape: &Rc<Tape>) -> Result<Tensor, EvalError> {
128	    let dims = x.value().shape().dims().to_vec();
129	    if dims.len() != 2 {
130	        return Err(EvalError::Unsupported(
131	            "rms_norm: input must be a rank-2 [rows, cols] matrix".into(),
132	        ));
133	    }
134	    let cols = dims[1];
135	    let eps = 1e-8_f64;
136	    let leaf = |v: DenseArray| Tensor::leaf(Rc::clone(tape), v, false);
137	    let ones_col = leaf(DenseArray::new(Shape::new(vec![cols, 1]), vec![1.0; cols])?);
138	    let ones_row = leaf(DenseArray::new(Shape::new(vec![1, cols]), vec![1.0; cols])?);
