    let names = model_params(&env, "attn").expect("attn is a model");
    assert_eq!(names.len(), 4);
    let wq = names[0].clone();
    let src = format!("grad(mean((apply(attn, X) - Y) * (apply(attn, X) - Y)), {wq})");
