/// after softmax, without introducing a new tape primitive.
fn causal_mask_array(seq: usize) -> Result<DenseArray, EvalError> {
    let neg = -1.0e9_f64;
    let mut data = vec![0.0_f64; seq * seq];
    for r in 0..seq {
