/// Set the strictly-upper triangle of a row-major `[seq, seq]` score
/// matrix to a large negative value so the subsequent softmax routes
/// ~all probability mass into the causally-valid positions.
fn apply_causal_mask(scores: &mut [f64], seq: usize) {
    let neg = -1.0e9_f64;
    for r in 0..seq {
        for c in (r + 1)..seq {
            scores[r * seq + c] = neg;
        }
    }
}

